Author: Jon Hasselgren <jhasselgren@nvidia.com>
Date:   Mon Jan 10 13:20:52 2022 +0100

    Illegal memory access fix for the optimized (cuda) image error metrics.
---
 src/renderutils/c_src/loss.cu            | 9 +++------
 src/renderutils/c_src/torch_bindings.cpp | 2 +-
 src/renderutils/ops.py                   | 2 +-
 3 files changed, 5 insertions(+), 8 deletions(-)

diff --git a/src/renderutils/c_src/loss.cu b/src/renderutils/c_src/loss.cu
index 7c89d6a..361c496 100644
--- a/src/renderutils/c_src/loss.cu
+++ b/src/renderutils/c_src/loss.cu
@@ -96,7 +96,7 @@ __global__ void imgLossFwdKernel(LossKernelParams p)
     unsigned int py = blockIdx.y * blockDim.y + threadIdx.y;
     unsigned int pz = blockIdx.z;

-    float floss = 0.0f, fmask = 0.0f;
+    float floss = 0.0f;
     if (px < p.gridSize.x && py < p.gridSize.y && pz < p.gridSize.z)
     {
         vec3f img = p.img.fetch3(px, py, pz);
@@ -122,10 +122,9 @@ __global__ void imgLossFwdKernel(LossKernelParams p)
             vloss = vec3f(abs(img.x - target.x), abs(img.y - target.y), abs(img.z - target.z));

         floss = sum(vloss) / 3.0f;
-        fmask = 1.0f;
     }

-    floss = warpSum(floss) / warpSum(fmask);
+    floss = warpSum(floss);

     dim3 warpSize = getWarpSize(blockDim);
     if (px < p.gridSize.x && py < p.gridSize.y && pz < p.gridSize.z && threadIdx.x % warpSize.x == 0 && threadIdx.y % warpSize.y == 0 && threadIdx.z % warpSize.z == 0)
@@ -139,8 +138,6 @@ __global__ void imgLossBwdKernel(LossKernelParams p)
     unsigned int py = blockIdx.y * blockDim.y + threadIdx.y;
     unsigned int pz = blockIdx.z;

-    float warp_elements = warpSum((px < p.gridSize.x&& py < p.gridSize.y&& pz < p.gridSize.z) ? 1.0f : 0.0f);
-
     if (px >= p.gridSize.x || py >= p.gridSize.y || pz >= p.gridSize.z)
         return;

@@ -163,7 +160,7 @@ __global__ void imgLossBwdKernel(LossKernelParams p)
     /////////////////////////////////////////////////////////////////////
     // BWD

-    vec3f d_vloss = vec3f(d_out, d_out, d_out) / (warp_elements * 3.0f);
+    vec3f d_vloss = vec3f(d_out, d_out, d_out) / 3.0f;

     vec3f d_img(0), d_target(0);
     if (p.loss == LOSS_MSE)
diff --git a/src/renderutils/c_src/torch_bindings.cpp b/src/renderutils/c_src/torch_bindings.cpp
index 46bf5fe..a479b71 100644
--- a/src/renderutils/c_src/torch_bindings.cpp
+++ b/src/renderutils/c_src/torch_bindings.cpp
@@ -663,7 +663,7 @@ torch::Tensor image_loss_fwd(torch::Tensor img, torch::Tensor target, std::strin

     // Allocate output tensors.
     torch::TensorOptions opts = torch::TensorOptions().dtype(p.out.fp16 ? torch::kBFloat16 : torch::kFloat32).device(torch::kCUDA);
-    torch::Tensor out = torch::empty({ p.gridSize.z / warpSize.z, p.gridSize.y / warpSize.y, p.gridSize.x / warpSize.x, 1 }, opts);
+    torch::Tensor out = torch::empty({ (p.gridSize.z - 1) / warpSize.z + 1, (p.gridSize.y - 1) / warpSize.y + 1, (p.gridSize.x - 1) / warpSize.x + 1, 1 }, opts);

     p.img = make_cuda_tensor(img, p.gridSize);
     p.target = make_cuda_tensor(target, p.gridSize);
diff --git a/src/renderutils/ops.py b/src/renderutils/ops.py
index d1f3f71..21c4383 100644
--- a/src/renderutils/ops.py
+++ b/src/renderutils/ops.py
@@ -358,7 +358,7 @@ def image_loss(img, target, loss='l1', tonemapper='none', use_python=False):
         out = image_loss_fn(img, target, loss, tonemapper)
     else:
         out = _image_loss_func.apply(img, target, loss, tonemapper)
-        out = torch.mean(out)
+        out = torch.sum(out) / (img.shape[0]*img.shape[1]*img.shape[2])

     if torch.is_anomaly_enabled():
         assert torch.all(torch.isfinite(out)), "Output of image_loss contains inf or NaN"
